int parse_json(const char* input, Value* result, int* pos) {
    if (input[*pos] == '{') {
        *pos += 1;
        return parse_object(input, result, pos);
    } else if (input[*pos] == '"') {
        return parse_string(input, result, pos);
    } else if (isdigit(input[*pos]) || input[*pos] == '-') {
        return parse_number(input, result, pos);
    } else if (input[*pos] == 't' || input[*pos] == 'f') {
        return parse_boolean(input, result, pos);
    } else if (input[*pos] == 'n') {
        result->type = VAL_NULL;
        *pos += 4;
        return 1;
    }
    return 0;
}

