int parse_number(const char* input, Value* result, int* pos) {
    char* end;
    result->type = VAL_NUMBER;
    result->u.number = strtod(input + *pos, &end);
    *pos = end - input;
    return 1;
}

int parse_boolean(const char* input, Value* result, int* pos) {
    if (strncmp(input + *pos, "true", 4) == 0) {
        result->type = VAL_BOOLEAN;
        result->u.boolean = 1;
        *pos += 4;
    } else if (strncmp(input + *pos, "false", 5) == 0) {
        result->type = VAL_BOOLEAN;
        result->u.boolean = 0;
        *pos += 5;
    }
    return 1;
}

int parse_object(const char* input, Value* result, int* pos) {
    result->type = VAL_OBJECT;
    result->u.object = (KeyValuePair*)malloc(sizeof(KeyValuePair));
    result->u.object->key = NULL;
    result->u.object->value = NULL;
