### 🧪 **Usage Example**

```c
int main() {
    const char* json = "{\"name\": \"Alice\", \"age\": 30, \"isStudent\": false}";
    Value result;
    int pos = 0;

    if (parse_json(json, &result, &pos)) {
        if (result.type == VAL_OBJECT) {
            KeyValuePair* obj = result.u.object;
            printf("Name: %s\n", obj->key);
            printf("Age: %f\n", obj->value->u.number);
            printf("Is Student: %d\n", obj->value->u.boolean);
        }
    } else {
        printf("Parsing failed.\n");
    }

    return 0;
}
```

